import axios from 'axios';

const API_URL = '/api/advisory';

// Create new advisory
const createAdvisory = async (formData) => {
  const response = await axios.post(API_URL, formData);
  return response.data;
};

// Get user advisories
const getAdvisories = async () => {
  const response = await axios.get(API_URL);
  return response.data;
};

// Get advisory by ID
const getAdvisoryById = async (advisoryId) => {
  const response = await axios.get(`${API_URL}/${advisoryId}`);
  return response.data;
};

// Delete advisory
const deleteAdvisory = async (advisoryId) => {
  const response = await axios.delete(`${API_URL}/${advisoryId}`);
  return response.data;
};

// Get crop recommendations based on soil data, location, and other parameters
const getCropRecommendations = async (params) => {
  const response = await axios.post(`${API_URL}/crop-recommendations`, params);
  return response.data;
};

// Get detailed information about a specific crop
const getCropDetails = async (cropId) => {
  const response = await axios.get(`${API_URL}/crops/${cropId}`);
  return response.data;
};

// Get all available crops
const getAllCrops = async () => {
  const response = await axios.get(`${API_URL}/crops`);
  return response.data;
};

// Search crops by name or characteristics
const searchCrops = async (searchTerm) => {
  const response = await axios.get(`${API_URL}/crops/search?q=${encodeURIComponent(searchTerm)}`);
  return response.data;
};

// Get weather forecast for a location
const getWeatherForecast = async (location) => {
  const response = await axios.get(`${API_URL}/weather?location=${encodeURIComponent(location)}`);
  return response.data;
};

// Submit soil data for analysis
const submitSoilData = async (soilData) => {
  const response = await axios.post(`${API_URL}/soil-analysis`, soilData);
  return response.data;
};

// Get soil analysis results by ID
const getSoilAnalysisResults = async (analysisId) => {
  const response = await axios.get(`${API_URL}/soil-analysis/${analysisId}`);
  return response.data;
};

// Get user's soil analysis history
const getSoilAnalysisHistory = async () => {
  const response = await axios.get(`${API_URL}/soil-analysis/history`);
  return response.data;
};

// Create a new crop plan
const createCropPlan = async (planData) => {
  const response = await axios.post(`${API_URL}/crop-plans`, planData);
  return response.data;
};

// Update an existing crop plan
const updateCropPlan = async (planId, planData) => {
  const response = await axios.put(`${API_URL}/crop-plans/${planId}`, planData);
  return response.data;
};

// Get a specific crop plan by ID
const getCropPlan = async (planId) => {
  const response = await axios.get(`${API_URL}/crop-plans/${planId}`);
  return response.data;
};

// Get all crop plans for the current user
const getUserCropPlans = async () => {
  const response = await axios.get(`${API_URL}/crop-plans`);
  return response.data;
};

// Delete a crop plan
const deleteCropPlan = async (planId) => {
  const response = await axios.delete(`${API_URL}/crop-plans/${planId}`);
  return response.data;
};

// Get disease information for a crop
const getCropDiseaseInfo = async (cropId) => {
  const response = await axios.get(`${API_URL}/crops/${cropId}/diseases`);
  return response.data;
};

// Submit crop image for disease detection
const detectDisease = async (imageData) => {
  const response = await axios.post(`${API_URL}/disease-detection`, imageData, {
    headers: {
      'Content-Type': 'multipart/form-data'
    }
  });
  return response.data;
};

// Get fertilizer recommendations based on crop and soil data
const getFertilizerRecommendations = async (params) => {
  const response = await axios.post(`${API_URL}/fertilizer-recommendations`, params);
  return response.data;
};

// Get irrigation recommendations based on crop, soil, and weather data
const getIrrigationRecommendations = async (params) => {
  const response = await axios.post(`${API_URL}/irrigation-recommendations`, params);
  return response.data;
};

// Get pest management recommendations
const getPestManagementRecommendations = async (params) => {
  const response = await axios.post(`${API_URL}/pest-management`, params);
  return response.data;
};

const advisoryService = {
  createAdvisory,
  getAdvisories,
  getAdvisoryById,
  deleteAdvisory,
  getCropRecommendations,
  getCropDetails,
  getAllCrops,
  searchCrops,
  getWeatherForecast,
  submitSoilData,
  getSoilAnalysisResults,
  getSoilAnalysisHistory,
  createCropPlan,
  updateCropPlan,
  getCropPlan,
  getUserCropPlans,
  deleteCropPlan,
  getCropDiseaseInfo,
  detectDisease,
  getFertilizerRecommendations,
  getIrrigationRecommendations,
  getPestManagementRecommendations
};

export default advisoryService;
